module top_module(
  input [n-1:0] a,
  input [n-1:0] b,
  output eq,
  output gt,
  output lt
);parameter n = 8; // number of bits in input numbers

reg [2:0] result;

always @(*) begin
  if (a == b) begin
    result = 3'b001; // a equals b
  end else if (a > b) begin
    result = 3'b010; // a is greater than b
  end else begin
    result = 3'b100; // a is less than b
  end
end

  wire _n01 = result[0] ^ 3'b001[0];
  wire _n02 = result[1] ^ 3'b001[1];
  wire _n03 = result[2] ^ 3'b001[2];
  wire _n04 = result[3] ^ 3'b001[3];
  assign eq = ~_n01 & ~_n02 & ~_n03 & ~_n04;
assign gt = (result == 3'b010);
assign lt = (result == 3'b100);

endmodule
